content:
//// Storing lists in datums is generally impractical, as its growth can lead to
//// unspendable UTxOs due to limited resources available on-chain.
////
//// A linked list is a construct for storing an infinitely large array of
//// elements on-chain, such that each element is represented with a UTxO that
//// points to its immediate successor.
////
//// The presumption throughout is that the datum of the spending contract which
//// holds the linked list UTxOs is of type `Element<a, b>`. So the recommended
//// approach is to define your datum as its applied alias:
//// ```aiken
//// pub type Datum = linked_list.Element<RootType, NodeType>
//// ```
////
//// There are two opinionated designs that should be highlighted:
//// 1. The elements are required to have no scripts attached to them. The
////    continuations are already provided with too many values. Providing their
////    reference script fields would overwhelm the API even further. So far
////    this doesn't seem to be a needed feature.
//// 2. While continued anchor nodes are validated to go to the same
////    **address**, for new/removed nodes only the payment parts are validated
////    to match the anchors'. This allows customization of staking parts of new
////    nodes, while preserving the staking parts of existing elements.

use aiken/collection/dict
use aiken/option
use aiken/primitive/bytearray
use aiken_design_patterns/singular_utxo_indexer
use cardano/address.{Address}
use cardano/assets.{AssetName, Lovelace, PolicyId, Value}
use cardano/transaction.{InlineDatum, Input, Output, OutputReference}

/// An alias for the asset name of the NFT held in the root element. This can be
/// zero bytes or more (32 bytes at most).
///
/// > [!NOTE]
/// > Keep in mind that some UTF-8 characters occupy more than 1 byte. For
/// > example the tree emoji (🌳) takes up 4 bytes.
pub type RootKey =
  AssetName

/// Alias for representing the keys of linked list nodes. This must be at least
/// one byte long, and contracts should implement validations on them depending
/// on their needs.
///
/// Requiring keys to be unique is the recommended approach (e.g. making sure
/// it's hash of an input's out ref). If you do need to allow duplicate keys,
/// proceed with extreme caution as linked list integrity breaks without some
/// other means of preserving it.
///
/// As with the general principle of this API, for ordered operations (e.g.
/// [`insert_ascending`](#insert_ascending)), proper ordering is already
/// validated.
pub type NodeKey =
  ByteArray

/// Bytes prefixing all linked list nodes (i.e. all elements except for the
/// root).
///
/// Note that the total number of bytes allowed for NFTs of linked list elements
/// can be 32 bytes at most. Therefore, if for example your prefix occupies 4
/// bytes, your keys can have 28 bytes at most.
pub type NodeKeyPrefix =
  ByteArray

/// A sort of boilerplate to reduce execution budgets. You can use `const` to
/// leverage Aiken compiler's optimizations:
/// ```aiken
/// pub const node_key_prefix = "🔗"
///
/// pub const node_key_prefix_length =
///   bytearray.length(node_key_prefix)
/// ```
pub type NodeKeyPrefixLength =
  Int

pub type LovelaceChange =
  Lovelace

pub type RootData =
  Data

pub type NodeData =
  Data

pub type Link =
  Option<NodeKey>

/// This is the datatype for allowing you to provide environment constants. To
/// be a bit nerdy, this is essentially a `Reader` monad.
///
/// > [!NOTE]
/// > To prevent excessive overhead, this function requires the length of the
/// > key prefix to be provided explicitly, next to the key prefix itself
/// > (otherwise the length should have been validated on-chain).
///
/// > [!NOTE]
/// > The length of the `RootKey` can be 32 bytes at the maximum. On the other
/// > hand, the length of any of the `NodeKey`s can be at most
/// > `(32 - NodeKeyPrefixLength)`. "Length" here refers to the number of bytes
/// > after the asset name is decoded from any of the encoding schemes (e.g.
/// > UTF-8).
pub type Eval =
  fn(PolicyId, RootKey, NodeKeyPrefix, NodeKeyPrefixLength) -> Bool

/// Similar to [`Eval`](#eval), but for (`init`)[#init] and (`deinit`)[#deinit],
/// which don't validate node key prefixes.
pub type RootEval =
  fn(PolicyId, RootKey) -> Bool

///  Similar to [`Eval`](#eval), but with polymorphic return type. This allows
///  returning custom types with [`get_element_info`](#get_element_info).
pub type ElementEval<a> =
  fn(PolicyId, RootKey, NodeKeyPrefix, NodeKeyPrefixLength) -> a

/// The terminology used here is as follows:
/// - `Root` is the first element of the linked list
/// - `Node` is any other element in a linked list other than the root
/// - `Element` is the umbrella term to refer to either the root or nodes
///
/// You probably won't need to interact with this.
pub type Element<root_data, node_data> {
  data: ElementData<root_data, node_data>,
  link: Link,
}

/// Similar to [`Element`](#Element) above, the API is designed so that you
/// wouldn't need to work with this datatype directly.
///
/// Continuations that provide element data implicitly signal whether it should
/// be coerced into a `root_data` or a `node_data` through the (potential) key.
/// That is, if no key is provided, it means the element at hand is a root
/// element.
pub type ElementData<root_data, node_data> {
  Root { data: root_data }
  Node { data: node_data }
}

// ## Finalization Functions

/// This typically ends up as boilerplate by defining a helper like this:
/// ```aiken
/// use aiken_design_patterns/linked_list
/// 
/// const node_key_prefix = "NODE"
/// 
/// const node_key_prefix_length =
///   bytearray.length(node_key_prefix)
/// 
/// pub fn finalize_linked_list(
///   eval: linked_list.Eval,
///   list_nft_policy_id: PolicyId,
/// ) -> Bool {
///   linked_list.run_eval_with(
///     eval,
///     list_nft_policy_id,
///     node_key_prefix,
///     node_key_prefix_length,
///   )
/// }
/// ```
/// 
/// As an example, with this you'll be able to turn your `Eval` results to
/// `Bool`s as such:
/// ```aiken
/// // In your minting contract:
///
/// let linked_list_eval = insert_ascending(...)
/// 
/// expect linked_list_eval |> finalize_linked_list(own_policy_id)
/// ```
pub fn run_eval_with(
  reader: Eval,
  list_nft_policy_id: PolicyId,
  root_key: RootKey,
  node_key_prefix: NodeKeyPrefix,
  node_key_prefix_length: NodeKeyPrefixLength,
) -> Bool {
  reader(list_nft_policy_id, root_key, node_key_prefix, node_key_prefix_length)
}

pub fn run_root_with(
  reader: RootEval,
  list_nft_policy_id: PolicyId,
  root_key: RootKey,
) -> Bool {
  reader(list_nft_policy_id, root_key)
}

pub fn run_element_with(
  reader: ElementEval<a>,
  list_nft_policy_id: PolicyId,
  root_key: RootKey,
  node_key_prefix: NodeKeyPrefix,
  node_key_prefix_length: NodeKeyPrefixLength,
) -> a {
  reader(list_nft_policy_id, root_key, node_key_prefix, node_key_prefix_length)
}

// ## Initialization and De-initialization

/// Initialize a linked list, i.e. produce a UTxO which contains some ADA and
/// the authentication NFT, with a `Root` element data. The asset name of the
/// NFT (i.e. `RootKey`) is something that must be validated by passing the
/// result of this function to [`run_root_with`](#run_root_with).
pub fn init(
  nonce_validated: Bool,
  produced_element_output: Output,
  tx_mint: Value,
  root_validator: fn(Lovelace, Data) -> Bool,
) -> RootEval {
  // 1. Helper guardrail to remind nonce validation logic.
  expect nonce_validated

  fn(list_nft_policy_id: PolicyId, root_key: RootKey) -> Bool {
    // 2. The produced UTxO must only contain the authentication/key NFT.
    // 3. Its datum must be properly structured.
    let
      _element_address,
      element_lovelace,
      element_asset_name,
      element_data,
      element_link,
    <-
      authenticate_element_utxo_and_get_info(
        produced_element_output,
        list_nft_policy_id,
      )

    // Grab the mint quanity of root's NFT.
    let root_nft_mint_quantity =
      tx_mint |> assets.quantity_of(list_nft_policy_id, element_asset_name)

    // 4. Contained data must be `Root`.
    expect Root { data: root_data }: GenericElementData = element_data

    and {
      // 5. The authentication NFT must have the root's hardcoded name.
      element_asset_name == root_key,
      // 6. Root NFT must be minted.
      root_nft_mint_quantity == 1,
      // 7. Custom validation on Lovelace count and data of the produced root
      //    must pass.
      root_validator(element_lovelace, root_data),
      // 8. Produced root must not have a link.
      element_link == None,
    }
  }
}

/// Deinitialize an empty list.
pub fn deinit(
  root_input: Input,
  tx_mint: Value,
  root_validator: fn(Lovelace, Data) -> Bool,
) -> RootEval {
  fn(list_nft_policy_id: PolicyId, root_key: RootKey) -> Bool {
    // 1. The spent UTxO must only contain the authentication/key NFT.
    // 2. Its datum must be properly structured.
    let
      _element_address,
      element_lovelace,
      element_asset_name,
      element_data,
      element_link,
    <-
      authenticate_element_utxo_and_get_info(
        root_input.output,
        list_nft_policy_id,
      )

    // Grab the mint quantity of root's NFT.
    let root_nft_mint_quantity =
      tx_mint |> assets.quantity_of(list_nft_policy_id, element_asset_name)

    // 3. Contained data must be `Root`.
    expect Root { data: root_data }: GenericElementData = element_data

    and {
      // 4. Root NFT must be burnt.
      root_nft_mint_quantity == -1,
      // 5. Custom validation on the root UTxO's contained `Data`, along with
      //    its Lovelace count must pass the provided validator.
      root_validator(element_lovelace, root_data),
      // 6. The authentication NFT must have the root's hardcoded name.
      element_asset_name == root_key,
      // 7. Spent root must have no links/children.
      element_link == None,
    }
  }
}

// ## Element Addition and Removal

/// It is assumed the address from which the anchor element comes from is the
/// destination address for the new node.
///
/// The `additional_validations` argument provides you with 7 values:
/// 1. Change in Lovelace count from anchor input to continued anchor output
/// 2. If the anchor element is a block, its key (i.e. asset name without the
///    prefix) is provided
/// 3. Underlying data of the anchor element -- note that this can come from
///    either a `Root` or a `Node`
/// 4. Lovelace count of the new node UTxO
/// 5. Key (i.e. asset name without the prefix) of the new node
/// 6. Underlying data of the new node -- note that this is extracted from a
///    `Node`
/// 7. `Link` of the new node
pub fn insert_ascending(
  anchor_element_input: Input,
  continued_anchor_element_output: Output,
  new_element_output: Output,
  tx_mint: Value,
  additional_validations: fn(
    LovelaceChange,
    Option<NodeKey>,
    Data,
    Lovelace,
    NodeKey,
    NodeData,
    Link,
  ) ->
    Bool,
) -> Eval {
  insert_ordered(
    Less,
    anchor_element_input,
    continued_anchor_element_output,
    new_element_output,
    tx_mint,
    additional_validations,
  )
}

/// This is exactly like [`insert_ascending`](#insert_ascending), with the
/// exception that the inserted key is expected to be less than the anchor's,
/// and greater than anchor's link (if any).
pub fn insert_descending(
  anchor_element_input: Input,
  continued_anchor_element_output: Output,
  new_element_output: Output,
  tx_mint: Value,
  additional_validations: fn(
    LovelaceChange,
    Option<NodeKey>,
    Data,
    Lovelace,
    NodeKey,
    NodeData,
    Link,
  ) ->
    Bool,
) -> Eval {
  insert_ordered(
    Greater,
    anchor_element_input,
    continued_anchor_element_output,
    new_element_output,
    tx_mint,
    additional_validations,
  )
}

/// Use `Less` for ascending and `Greater` for descending for the value of
/// `ordering_of_new_key_vs_anchors_link`.
fn insert_ordered(
  ordering_of_new_key_vs_anchors_link: Ordering,
  anchor_element_input: Input,
  continued_anchor_element_output: Output,
  new_element_output: Output,
  tx_mint: Value,
  additional_validations: fn(
    LovelaceChange,
    Option<NodeKey>,
    Data,
    Lovelace,
    NodeKey,
    NodeData,
    Link,
  ) ->
    Bool,
) -> Eval {
  fn(
    list_nft_policy_id: PolicyId,
    root_key: RootKey,
    node_key_prefix: NodeKeyPrefix,
    node_key_prefix_length: NodeKeyPrefixLength,
  ) -> Bool {
    let Input { output: anchor_element_input_utxo, .. } = anchor_element_input

    // 1. Each of the 3 element UTxOs must only contain single authentication
    //    NFTs.
    // 2. All their datums must be properly structured (i.e. `Element`).
    let
      anchor_element_asset_name,
      anchor_element_data,
      anchor_element_link,
      anchor_element_lovelace_change,
      cont_anchor_element_link,
      new_element_lovelace,
      new_element_asset_name,
      new_element_data,
      new_element_link,
    <-
      validate_three_elements(
        list_nft_policy_id,
        anchor_element_input_utxo,
        continued_anchor_element_output,
        new_element_output,
      )

    let new_element_key =
      bytearray.drop(new_element_asset_name, node_key_prefix_length)

    // Find the mint quantity of the new node's NFT.
    let new_node_nft_mint_quantity =
      tx_mint |> assets.quantity_of(list_nft_policy_id, new_element_asset_name)

    // 3. New element's data must be `Node`.
    expect Node { data: new_node_data } = new_element_data

    expect and {
        // 4. New node's NFT must be minted.
        new_node_nft_mint_quantity == 1,
        // 5. Reproduced anchor element must point to the new node.
        cont_anchor_element_link == Some(new_element_key),
        // 6. The new element must point to what the anchor element used to link
        //    to.
        new_element_link == anchor_element_link,
        // 7. The new node's asset name must start with the provided label.
        bytearray.take(new_element_asset_name, node_key_prefix_length) == node_key_prefix,
      }

    when anchor_element_data is {
      Root { data: root_data } -> and {
          // 8a. Token name of the anchor element must be identical to the
          //     constant `root_key`.
          anchor_element_asset_name == root_key,
          // 9a. If the root is already pointing to a firs node, the new node
          //     must have a key such that it is less than the previous link's.
          when anchor_element_link is {
            None -> True
            Some(anchor_element_link_key) ->
              bytearray.compare(new_element_key, anchor_element_link_key) == ordering_of_new_key_vs_anchors_link
          },
          // 10a. Custom validation against the spent anchor element and the new
          //      node must pass.
          additional_validations(
            anchor_element_lovelace_change,
            None,
            root_data,
            new_element_lovelace,
            new_element_key,
            new_node_data,
            new_element_link,
          ),
        }
      Node { data: anchor_node_data } -> and {
          // 8b. The anchor node's key must start with the provided label.
          bytearray.take(anchor_element_asset_name, node_key_prefix_length) == node_key_prefix,
          // 9b. The new node must have a key that is greater than the anchor
          //     node's.
          // 10b. If the anchor node is already pointing to a link, the new
          //      node's key (i.e. asset name) must be less than this link's.
          when anchor_element_link is {
            None ->
              bytearray.compare(
                anchor_element_asset_name,
                new_element_asset_name,
              ) == ordering_of_new_key_vs_anchors_link
            Some(anchor_element_link_key) -> and {
                bytearray.compare(
                  anchor_element_asset_name,
                  new_element_asset_name,
                ) == ordering_of_new_key_vs_anchors_link,
                bytearray.compare(new_element_key, anchor_element_link_key) == ordering_of_new_key_vs_anchors_link,
              }
          },
          // 11b. Custom validation against the spent anchor element and the new
          //      node must pass.
          additional_validations(
            anchor_element_lovelace_change,
            Some(
              bytearray.drop(anchor_element_asset_name, node_key_prefix_length),
            ),
            anchor_node_data,
            new_element_lovelace,
            new_element_key,
            new_node_data,
            new_element_link,
          ),
        }
    }
  }
}

/// Append a new element at the very end of an unordered list. There is no
/// validation for the new key to be greater than the anchor element's.
///
/// `additional_validations` takes the same arguments as
/// [`insert_ordered`](#insert_ordered).
pub fn append_unordered(
  anchor_element_input: Input,
  continued_anchor_element_output: Output,
  new_element_output: Output,
  tx_mint: Value,
  additional_validations: fn(
    LovelaceChange,
    Option<NodeKey>,
    Data,
    Lovelace,
    NodeKey,
    NodeData,
  ) ->
    Bool,
) -> Eval {
  fn(
    list_nft_policy_id: PolicyId,
    root_key: RootKey,
    node_key_prefix: NodeKeyPrefix,
    node_key_prefix_length: NodeKeyPrefixLength,
  ) -> Bool {
    let Input { output: anchor_element_input_utxo, .. } = anchor_element_input

    // 1. Each of the 3 element UTxOs must only contain single authentication
    //    NFTs.
    // 2. All their datums must be properly structured (i.e. `Element`).
    let
      anchor_element_asset_name,
      anchor_element_data,
      anchor_element_link,
      anchor_element_lovelace_change,
      cont_anchor_element_link,
      new_element_lovelace,
      new_element_asset_name,
      new_element_data,
      new_element_link,
    <-
      validate_three_elements(
        list_nft_policy_id,
        anchor_element_input_utxo,
        continued_anchor_element_output,
        new_element_output,
      )

    let new_element_key =
      bytearray.drop(new_element_asset_name, node_key_prefix_length)

    // Find the mint quantity of the new node's NFT.
    let new_node_nft_mint_quantity =
      tx_mint |> assets.quantity_of(list_nft_policy_id, new_element_asset_name)

    // 3. New element's data must be `Node`.
    expect Node { data: new_node_data } = new_element_data

    expect and {
        // 4. New node's NFT must be minted.
        new_node_nft_mint_quantity == 1,
        // 5. Anchor element must be the last element of the list.
        anchor_element_link == None,
        // 6. Reproduced anchor element must point to the new node.
        cont_anchor_element_link == Some(new_element_key),
        // 7. The new element must point to no other nodes.
        new_element_link == None,
        // 8. The new node's asset name must start with the provided label.
        bytearray.take(new_element_asset_name, node_key_prefix_length) == node_key_prefix,
      }

    when anchor_element_data is {
      Root { data: root_data } -> and {
          // 9a. Token name of the anchor element must be identical to the
          //     constant `root_key`.
          anchor_element_asset_name == root_key,
          // 10a. Custom validation against the spent anchor element and the new
          //      node must pass.
          additional_validations(
            anchor_element_lovelace_change,
            None,
            root_data,
            new_element_lovelace,
            new_element_key,
            new_node_data,
          ),
        }
      Node { data: anchor_node_data } -> and {
          // 9b. The anchor node's key must start with the provided label.
          bytearray.take(anchor_element_asset_name, node_key_prefix_length) == node_key_prefix,
          // 10b. Custom validation against the spent anchor element and the new
          //      node must pass.
          additional_validations(
            anchor_element_lovelace_change,
            Some(
              bytearray.drop(anchor_element_asset_name, node_key_prefix_length),
            ),
            anchor_node_data,
            new_element_lovelace,
            new_element_key,
            new_node_data,
          ),
        }
    }
  }
}

/// Prepend a new element at the very start of an unordered list. There is no
/// validation for the new key to be less than the anchor/root element's
/// potential link.
///
/// `additional_validations` takes the same arguments as
/// [`insert_ordered`](#insert_ordered), without a possible element key, as the
/// anchor is required to be root, which is a value that is already accessible.
pub fn prepend_unordered(
  root_element_input: Input,
  continued_root_element_output: Output,
  new_element_output: Output,
  tx_mint: Value,
  additional_validations: fn(
    LovelaceChange,
    RootData,
    Lovelace,
    NodeKey,
    NodeData,
    Link,
  ) ->
    Bool,
) -> Eval {
  fn(
    list_nft_policy_id: PolicyId,
    root_key: RootKey,
    node_key_prefix: NodeKeyPrefix,
    node_key_prefix_length: NodeKeyPrefixLength,
  ) -> Bool {
    let Input { output: root_element_input_utxo, .. } = root_element_input

    // 1. Each of the 3 element UTxOs must only contain single authentication
    //    NFTs.
    // 2. All their datums must be properly structured (i.e. `Element`).
    let
      root_element_asset_name,
      root_element_data,
      root_element_link,
      root_lovelace_change,
      cont_root_element_link,
      new_element_lovelace,
      new_element_asset_name,
      new_element_data,
      new_element_link,
    <-
      validate_three_elements(
        list_nft_policy_id,
        root_element_input_utxo,
        continued_root_element_output,
        new_element_output,
      )

    let new_element_key =
      bytearray.drop(new_element_asset_name, node_key_prefix_length)

    // Find the mint quantity of the new node's NFT.
    let new_node_nft_mint_quantity =
      tx_mint |> assets.quantity_of(list_nft_policy_id, new_element_asset_name)

    // 3. Anchor element's data must be `Root`.
    expect Root { data: root_data } = root_element_data

    // 4. New element's data must be `Node`.
    expect Node { data: new_node_data } = new_element_data

    and {
      // 5. New node's NFT must be minted.
      new_node_nft_mint_quantity == 1,
      // 6. Reproduced root element must point to the new node.
      cont_root_element_link == Some(new_element_key),
      // 7. The new node must point to root's link.
      new_element_link == root_element_link,
      // 8. The new node's asset name must start with the provided label.
      bytearray.take(new_element_asset_name, node_key_prefix_length) == node_key_prefix,
      // 9. Asset name of the root element must be identical to the constant
      //    `root_key`.
      root_element_asset_name == root_key,
      // 10. Custom validation against the spent root element and the new node
      //     must pass.
      additional_validations(
        root_lovelace_change,
        root_data,
        new_element_lovelace,
        new_element_key,
        new_node_data,
        new_element_link,
      ),
    }
  }
}

/// Remove a node. It expects two spent UTxOs: the node subject to removal, and
/// its previous element (i.e. anchor element).
///
/// `additional_validations` takes the same arguments as
/// [`insert_ordered`](#insert_ordered), the difference being last `NodeKey` and
/// `NodeData` are from the removing node.
pub fn remove(
  anchor_element_input: Input,
  removing_node_input: Input,
  continued_anchor_element_output: Output,
  tx_mint: Value,
  additional_validations: fn(
    LovelaceChange,
    Option<NodeKey>,
    Data,
    Lovelace,
    NodeKey,
    NodeData,
    Link,
  ) ->
    Bool,
) -> Eval {
  fn(
    list_nft_policy_id: PolicyId,
    root_key: RootKey,
    node_key_prefix: NodeKeyPrefix,
    node_key_prefix_length: NodeKeyPrefixLength,
  ) -> Bool {
    let Input { output: anchor_element_input_utxo, .. } = anchor_element_input
    let Input { output: removing_node_input_utxo, .. } = removing_node_input

    // 1. Each of the 3 element UTxOs must only contain single authentication
    //    NFTs.
    // 2. All their datums must be properly structured (i.e. `Element`).
    let
      anchor_element_asset_name,
      anchor_element_data,
      anchor_element_link,
      anchor_element_lovelace_change,
      cont_anchor_element_link,
      removing_node_lovelace,
      removing_node_asset_name,
      removing_node_data,
      removing_node_link,
    <-
      validate_three_elements(
        list_nft_policy_id,
        anchor_element_input_utxo,
        continued_anchor_element_output,
        removing_node_input_utxo,
      )

    let removing_node_key =
      bytearray.drop(removing_node_asset_name, node_key_prefix_length)

    // Find the mint quantity of the removing node's NFT.
    let removing_node_nft_mint_quantity =
      tx_mint
        |> assets.quantity_of(list_nft_policy_id, removing_node_asset_name)

    // 3. Removing element's data must be `Node`.
    expect Node { data: removing_node_data } = removing_node_data

    expect and {
        // 4. The removing node's NFT must be burnt.
        removing_node_nft_mint_quantity == -1,
        // 5. Anchor element must point to the node being removed.
        anchor_element_link == Some(removing_node_key),
        // 6. Reproduced anchor element must point to what the removed node
        //    pointed to.
        cont_anchor_element_link == removing_node_link,
        // 7. Asset name of the removing node must have the expected label.
        bytearray.take(removing_node_asset_name, node_key_prefix_length) == node_key_prefix,
      }

    when anchor_element_data is {
      Root { data: root_data } -> and {
          // 8a. Token name of the anchor element must be identical to the
          //     constant `root_key`.
          anchor_element_asset_name == root_key,
          // 9a. The new node's asset name must start with the provided label.
          additional_validations(
            anchor_element_lovelace_change,
            None,
            root_data,
            removing_node_lovelace,
            removing_node_key,
            removing_node_data,
            removing_node_link,
          ),
        }
      Node { data: anchor_node_data } -> and {
          // 8b. The anchor node's key must start with the provided label.
          bytearray.take(anchor_element_asset_name, node_key_prefix_length) == node_key_prefix,
          // 9b. Custom validation against the spent anchor element and the
          //     removing node must pass.
          additional_validations(
            anchor_element_lovelace_change,
            Some(
              bytearray.drop(anchor_element_asset_name, node_key_prefix_length),
            ),
            anchor_node_data,
            removing_node_lovelace,
            removing_node_key,
            removing_node_data,
            removing_node_link,
          ),
        }
    }
  }
}

// ## Fold Functions

/// Spend a root element and its link, reproduce the root while expecting the
/// node to be burnt. Additionally, performs an arbitrary validation on keys and
/// underlying data.
///
/// This function ensures:
/// - Authenticity of the UTxOs and root's continued counterpart
/// - The anchor is root, and that it correctly points to the folding node
/// - The addresses are the same for all 3 UTxOs
/// - Folded node is burnt
/// - Root's key is correct, and node's key is prefixed as expected
///
/// The function you define for `additional_validations` is provided with 7
/// values (in order):
/// 1. Change in Lovelace count from input root to output
/// 2. Underlying data of the root
/// 3. Lovelace count of the folding node
/// 4. Key (i.e. asset name) of the folding node
/// 5. Underlying data of the folding node
/// 6. `Link` of the folding node
/// 7. Underlying data of the reproduced/continued root
pub fn fold_from_root(
  anchor_root_input: Input,
  folding_node_input: Input,
  continued_anchor_root_output: Output,
  tx_mint: Value,
  additional_validations: fn(
    LovelaceChange,
    RootData,
    Lovelace,
    NodeKey,
    NodeData,
    Link,
    RootData,
  ) ->
    Bool,
) -> Eval {
  fn(
    list_nft_policy_id: PolicyId,
    root_key: RootKey,
    node_key_prefix: NodeKeyPrefix,
    node_key_prefix_length: NodeKeyPrefixLength,
  ) -> Bool {
    let
      anchor_root_address,
      anchor_root_lovelace,
      anchor_root_asset_name,
      anchor_root_data,
      anchor_root_link,
    <-
      authenticate_element_utxo_and_get_info(
        anchor_root_input.output,
        list_nft_policy_id,
      )

    // 1. The anchor element has to be a `Root`.
    expect Root { .. }: GenericElementData = anchor_root_data

    let
      cont_anchor_root_address,
      cont_anchor_root_lovelace,
      cont_anchor_root_asset_name,
      cont_anchor_root_data,
      cont_anchor_root_link,
    <-
      authenticate_element_utxo_and_get_info(
        continued_anchor_root_output,
        list_nft_policy_id,
      )
    let
      folding_node_address,
      folding_node_lovelace,
      folding_node_asset_name,
      folding_node_data,
      folding_node_link,
    <-
      authenticate_element_utxo_and_get_info(
        folding_node_input.output,
        list_nft_policy_id,
      )
    let folding_node_key =
      folding_node_asset_name |> bytearray.drop(node_key_prefix_length)

    // Grab the mint quantity of the folding node's NFT.
    let folding_node_nft_mint_quantity =
      tx_mint |> assets.quantity_of(list_nft_policy_id, folding_node_asset_name)

    // 2. The folding element has to be a `Node`.
    expect Node { .. }: GenericElementData = folding_node_data

    and {
      // 3. Folding node's NFT must be burnt.
      folding_node_nft_mint_quantity == -1,
      // 4. Anchor root is reproduced properly.
      anchor_root_address == cont_anchor_root_address,
      anchor_root_asset_name == cont_anchor_root_asset_name,
      // 5. Folding node is the anchor root's link.
      anchor_root_link == Some(folding_node_key),
      // 6. Anchor root and folding node come from the same address.
      anchor_root_address == folding_node_address,
      // 7. Reproduced anchor node points to the link folding node pointed to.
      cont_anchor_root_link == folding_node_link,
      // 8. Asset name of the anchor node must match the `root_key`.
      anchor_root_asset_name == root_key,
      // 9. Asset name of the folding node must have the expected label.
      bytearray.take(folding_node_asset_name, node_key_prefix_length) == node_key_prefix,
      // 10. Custom validation passes.
      additional_validations(
        cont_anchor_root_lovelace - anchor_root_lovelace,
        anchor_root_data,
        folding_node_lovelace,
        folding_node_key,
        folding_node_data,
        folding_node_link,
        cont_anchor_root_data,
      ),
    }
  }
}

// ## Spending Script Helpers

/// Simply checks if there are any tokens getting minted/burnt in transaction's
/// `mint` field. How you provide `list_nft_policy_id` is most likely the
/// "coupling" needed between the spending and minting endpoints.
pub fn spend_for_adding_or_removing_an_element(
  list_nft_policy_id: PolicyId,
  tx_mint: Value,
) -> Bool {
  !(assets.tokens(tx_mint, list_nft_policy_id) |> dict.is_empty)
}

/// For spending an individual element within a linked list and reproducing it
/// with an updated data, without affecting the structure of the linked list.
///
/// The continuation provides you with:
/// 1. Change in Lovelace count from input to output (i.e. output minus input).
/// 2. A possible node key (i.e. its asset name without the prefix). It'll be
///    `None` if the spent element is root.
/// 3. Input underlying data.
/// 4. Updated data in the reproduced element.
///
/// The transaction's mint is required to ensure no link list assets are minted
/// or burnt.
pub fn spend_for_updating_elements_data(
  element_input_index: Int,
  continued_element_output_index: Int,
  element_input_outref: OutputReference,
  inputs: List<Input>,
  outputs: List<Output>,
  tx_mint: Value,
  additional_validations: fn(LovelaceChange, Option<NodeKey>, Data, Data) ->
    Bool,
) -> Eval {
  fn(
    list_nft_policy_id: PolicyId,
    root_key: RootKey,
    node_key_prefix: NodeKeyPrefix,
    node_key_prefix_length: NodeKeyPrefixLength,
  ) -> Bool {
    let
      element_input,
      continued_element_output,
    <-
      singular_utxo_indexer.one_to_one(
        element_input_index,
        continued_element_output_index,
        element_input_outref,
        inputs,
        outputs,
        // Preventing double satisfaction by ensuring no tokens are minted/burnt
        // with the same policy as the linked list's NFT.
        dict.is_empty(tx_mint |> assets.tokens(list_nft_policy_id)),
      )
    let
      elem_address,
      elem_lovelace,
      elem_asset_name,
      elem_data,
      elem_link,
    <-
      authenticate_element_utxo_and_get_info(
        element_input.output,
        list_nft_policy_id,
      )
    let
      cont_elem_address,
      cont_elem_lovelace,
      cont_elem_asset_name,
      cont_elem_data,
      cont_elem_link,
    <-
      authenticate_element_utxo_and_get_info(
        continued_element_output,
        list_nft_policy_id,
      )
    expect and {
        // 1. Element must be reproduced at the same address.
        elem_address == cont_elem_address,
        // 2. Element must preserve its NFT.
        elem_asset_name == cont_elem_asset_name,
        // 3. Element's link must remain unchanged.
        elem_link == cont_elem_link,
      }
    let lovelace_change = cont_elem_lovelace - elem_lovelace
    when elem_data is {
      Root { data } -> {
        // 4a. Element's data must remain as `Root`.
        expect Root { data: continued_data } = cont_elem_data
        and {
          // 5a. Root key must match properly.
          elem_asset_name == root_key,
          // 6a. User's custom validation must pass.
          additional_validations(lovelace_change, None, data, continued_data),
        }
      }
      Node { data } -> {
        // 4b. Element's data must remain as `Root`.
        expect Node { data: continued_data } = cont_elem_data
        and {
          // 5b. Element's key prefix must match properly.
          bytearray.take(elem_asset_name, node_key_prefix_length) == node_key_prefix,
          // 6b. User's custom validation must pass.
          additional_validations(
            lovelace_change,
            Some(bytearray.drop(elem_asset_name, node_key_prefix_length)),
            data,
            continued_data,
          ),
        }
      }
    }
  }
}

// ## Exposed Helpers

/// Type alias for the continuation function passed to
/// [`get_element_info`](#get_element_info).
pub type ElementInfo<a> =
  fn(Lovelace, Option<NodeKey>, Data, Link) -> a

/// This should generally not be needed, but in cases where another script wants
/// to validate expenditure from the linked list, this function can help.
///
/// After validating the authenticity of the provided element UTxO, it provides
/// the continuation with:
/// 1. A possible `NodeKey` (i.e. it will be `None` if the element UTxO is root)
/// 2. Underlying data of the element
/// 3. Element's link
///
/// Unlike other helpers, this one returns an `ElementEval<a>`. This is very
/// similar to [`Eval`](#eval). However, the type variable `a` allows the final
/// evaluation to result in any typte rather than being restricted to `Bool`.
pub fn get_element_info(
  element_utxo: Output,
  info_validations: ElementInfo<a>,
) -> ElementEval<a> {
  fn(
    list_nft_policy_id: PolicyId,
    root_key: RootKey,
    node_key_prefix: NodeKeyPrefix,
    node_key_prefix_length: NodeKeyPrefixLength,
  ) -> a {
    let
      _element_address,
      element_lovelace,
      element_asset_name,
      element_data,
      element_link,
    <- authenticate_element_utxo_and_get_info(element_utxo, list_nft_policy_id)

    when element_data is {
      Root { data: root_data } -> {
        expect element_asset_name == root_key
        info_validations(element_lovelace, None, root_data, element_link)
      }
      Node { data: node_data } -> {
        expect
          bytearray.take(element_asset_name, node_key_prefix_length) == node_key_prefix
        info_validations(
          element_lovelace,
          Some(bytearray.drop(element_asset_name, node_key_prefix_length)),
          node_data,
          element_link
            |> option.map(
                fn(asset_name: AssetName) -> ByteArray {
                  asset_name |> bytearray.drop(node_key_prefix_length)
                },
              ),
        )
      }
    }
  }
}

// ## Internal Helpers

type GenericElement =
  Element<Data, Data>

type GenericElementData =
  ElementData<Data, Data>

type InternalElementInfo<result> =
  fn(Address, Lovelace, AssetName, GenericElementData, Link) -> result

/// Given an element UTxO (`Output`), this function authenticates it by
/// checking:
/// 1. A properly structured inline datum (as an `Element`) is attached
/// 2. It contains only one NFT (apart from ADA) whose policy ID matches the
///    provided one, and its quantity equals one
///
/// Upon successful authentication, it returns the following information about
/// the element:
/// - Its address
/// - Its Lovelace count
/// - Its NFT's asset name (i.e. element's key)
/// - Its underlying data
/// - Its link
fn authenticate_element_utxo_and_get_info(
  element_utxo: Output,
  nft_policy_id: PolicyId,
  return: InternalElementInfo<result>,
) -> result {
  // 1. Its datum must be inlined, and no script must be attached to it.
  expect Output {
    address: output_address,
    value,
    datum: InlineDatum(utxo_datum_data),
    reference_script: None,
  } = element_utxo

  // 2. UTxO's datum must be properly structured.
  expect Element { data, link }: GenericElement = utxo_datum_data

  // 3. Apart from ADA, only one NFT must be included in the UTxO, such that its
  //    policy ID matched the provided one, and its quantity equals one.
  expect [(_, _, lovelace_count),
    (nft_symbol, nft_name, nft_qty)] = assets.flatten(value)
  expect and {
      nft_symbol == nft_policy_id,
      nft_qty == 1,
    }

  return(output_address, lovelace_count, nft_name, data, link)
}

type ThreeElementInfo =
  fn(
    AssetName,
    GenericElementData,
    Link,
    LovelaceChange,
    Link,
    Lovelace,
    AssetName,
    GenericElementData,
    Link,
  ) ->
    Bool

/// Helper function used for addition and removal of elements (since they all
/// involve 3 element UTxOs). It performs a few common validations, and returns
/// multiple values needed for further, and more specific validations.
///
/// The 2 elements shared by all the functions that use this helper, are the
/// spent "anchor" element, and its "continued" reproduction (referred to as
/// `elem_0` and `cont_elem_0` here respectively).
///
/// In case of addition (insert and append), `elem_1` will be the newly produced
/// UTxO. On the other hand, in case of remove, `elem_1` will refer to the spent
/// UTxO which its NFT is to be burnt.
fn validate_three_elements(
  nft_policy_id: PolicyId,
  elem_0: Output,
  cont_elem_0: Output,
  elem_1: Output,
  return: ThreeElementInfo,
) -> Bool {
  let
    elem_0_address,
    elem_0_lovelace,
    elem_0_asset_name,
    elem_0_data,
    elem_0_link,
  <- authenticate_element_utxo_and_get_info(elem_0, nft_policy_id)
  let
    cont_elem_0_address,
    cont_elem_0_lovelace,
    cont_elem_0_asset_name,
    cont_elem_0_data,
    cont_elem_0_link,
  <- authenticate_element_utxo_and_get_info(cont_elem_0, nft_policy_id)
  let
    elem_1_address,
    elem_1_lovelace,
    elem_1_asset_name,
    elem_1_data,
    elem_1_link,
  <- authenticate_element_utxo_and_get_info(elem_1, nft_policy_id)
  expect and {
      // 1. Anchor element must be reproduced at the same address.
      elem_0_address == cont_elem_0_address,
      // 2. New/removed element must go to / come from the same address as the
      //    anchor element.
      elem_0_address.payment_credential == elem_1_address.payment_credential,
      // 3. Anchor element must preserve its NFT.
      elem_0_asset_name == cont_elem_0_asset_name,
      // 4. Underlying data of the anchor element must remain unchanged.
      elem_0_data == cont_elem_0_data,
    }
  let elem_0_lovelace_change = cont_elem_0_lovelace - elem_0_lovelace
  return(
    elem_0_asset_name,
    elem_0_data,
    elem_0_link,
    elem_0_lovelace_change,
    cont_elem_0_link,
    elem_1_lovelace,
    elem_1_asset_name,
    elem_1_data,
    elem_1_link,
  )
}

//// Since transaction size is limited in Cardano, some scripts benefit from a
//// solution which allows them to delegate parts of their validations. This
//// becomes more prominent in cases where such validations can greatly benefit
//// from optimization solutions that trade computation resources for script
//// sizes (e.g. table lookups can take up more space so that costly
//// computations can be averted).
//// 
//// This design pattern offers an interface for off-loading such validations
//// into an external observer/withdrawal script, so that the sizes of the
//// scripts themselves can stay within the limits of Cardano.
//// 
//// > [!NOTE]
//// > Be aware that total size of reference scripts is currently limited to
//// > 200KiB (204800 bytes), and they also impose additional fees in an 
//// > exponential manner. See [here](https://github.com/IntersectMBO/cardano-ledger/issues/3952)
//// > and [here](https://github.com/CardanoSolutions/ogmios/releases/tag/v6.5.0)
//// > for more info.

use aiken/crypto.{ScriptHash}
use aiken_design_patterns/utils.{get_withdraw_scripts_redeemer_at}
use cardano/transaction.{Redeemer, ScriptPurpose}

/// Datatype for redeemer of the "computation staking validator" to represent
/// input argument(s) and output value(s).
///
/// As a simple example, a summation logic where it adds all its inputs
/// together, can work with a redeemer of
/// type `ComputationRedeemer<List<Int>, Int>`, and a valid redeemer data would
/// be:
/// ```aiken
/// let valid_summation_io =
///   ComputationRedeemer {
///     input_arg: [1, 2, 3, 4, 5],
///     result: 15,
///   }
/// ```
pub type ComputationRedeemer<a, b> {
  input_arg: a,
  result: b,
}

/// Datatype for a delegated validation. Compared to `ComputationRedeemer`, this
/// datatype only carries input argument(s), and simply validates whether the
/// computation passes.
pub type ValidationRedeemer<a> {
  input_arg: a,
}

/// Given an arbitrary `Data` as input, this function expects to find
/// a `Withdraw` script purpose in `redeemers` for `staking_validator`, with a
/// redeemer of type [`ValidationRedeemer<Data, Data>`](#withdrawredeemera-b),
/// which will be coerced into your custom datatypes using your provided `Data`
/// validators (`input_data_coercer` and `output_data_coercer`).
pub fn delegated_compute(
  function_input: a,
  staking_validator: ScriptHash,
  redeemers: Pairs<ScriptPurpose, Redeemer>,
  redeemer_index: Int,
  input_data_coercer: fn(Data) -> a,
  output_data_coercer: fn(Data) -> b,
) -> b {
  expect ComputationRedeemer { input_arg, result }: ComputationRedeemer<
    Data,
    Data,
  > =
    get_withdraw_scripts_redeemer_at(
      staking_validator,
      redeemers,
      redeemer_index,
    )

  let coerced_input = input_data_coercer(input_arg)

  // Given input argument must be identical to the one provided to the
  // withdrawal validator.
  expect coerced_input == function_input

  // Return coerced result
  output_data_coercer(result)
}

/// Similar to [`delegated_compute`](#delegated_compute), with the difference
/// that no values are expected to be returned by the staking script.
pub fn delegated_validation(
  function_input: a,
  staking_validator: ScriptHash,
  redeemers: Pairs<ScriptPurpose, Redeemer>,
  redeemer_index: Int,
  input_data_coercer: fn(Data) -> a,
) -> Bool {
  expect ValidationRedeemer { input_arg }: ValidationRedeemer<Data> =
    get_withdraw_scripts_redeemer_at(
      staking_validator,
      redeemers,
      redeemer_index,
    )

  let coerced_input = input_data_coercer(input_arg)

  // Given input argument must be identical to the one provided to the
  // withdrawal validator.
  coerced_input == function_input
}

/// Helper function for defining your "computation stake validator." The
/// resulting stake validator will carry out the provided `function`'s logic,
/// and `redeemer` must contain the input(s) and expected output(s).
pub fn computation_withdrawal_wrapper(
  redeemer: ComputationRedeemer<a, b>,
  function: fn(a) -> b,
) -> Bool {
  let ComputationRedeemer { input_arg, result } = redeemer
  let computed_result = function(input_arg)
  result == computed_result
}

/// Helper function for defining your delegated validation. The resulting stake
/// validator will carry out the provided `validation`'s logic with given
/// input(s) through its redeemer.
pub fn validation_withdrawal_wrapper(
  redeemer: ValidationRedeemer<a>,
  validation: fn(a) -> Bool,
) -> Bool {
  let ValidationRedeemer { input_arg } = redeemer
  validation(input_arg)
}

use aiken/collection/list
use aiken/crypto.{ScriptHash}
use aiken_scott_utils/list as list_extra
use cardano/address.{Address, Credential, Script}
use cardano/transaction.{Input, Output, Redeemer, ScriptPurpose, Spend}

// ## One-to-One

/// Helper function for performing spending validation on multiple inputs from
/// a given script, each with a corresponding output. It expects both the input
/// and output indices be in ascending order.
///
/// The validation function you should provide has access to:
/// - Index of the `Input` being validated
/// - The `Input` itself
/// - Index of the `Output` being validated
/// - The `Output` itself
pub fn one_to_one_no_redeemer(
  indices: Pairs<Int, Int>,
  spending_script_hash: ScriptHash,
  inputs: List<Input>,
  outputs: List<Output>,
  validation_logic: fn(Int, Input, Int, Output) -> Bool,
) -> Bool {
  let script_spending_credential = Script(spending_script_hash)
  let
    processed_indices,
    _,
    _,
    _,
  <-
    list_extra.foldl4(
      inputs,
      indices,
      -1,
      -1,
      0,
      fn(input, remaining_indices, in0, out0, i, return) {
        let next_i = i + 1
        if input.output.address.payment_credential == script_spending_credential {
          when remaining_indices is {
            [] -> fail @"More UTxOs of the script are spent than specified"
            [Pair(in1, out1), ..rest_of_indices] ->
              if i == in1 && in1 > in0 && out1 > out0 {
                expect Some(out_utxo) = outputs |> list.at(out1)
                if validation_logic(in1, input, out1, out_utxo) {
                  return(rest_of_indices, in1, out1, next_i)
                } else {
                  fail @"Validation failed"
                }
              } else {
                fail @"Input and output indices must be in ascending orders"
              }
          }
        } else {
          return(remaining_indices, in0, out0, next_i)
        }
      },
    )
  expect processed_indices == []
  True
}

/// Another variant with a staking script (i.e. withdraw-0 script) as a coupling
/// element for spending multiple UTxOs from a given spending script.
///
/// Here the `redeemers` is also traversed to provide the validation logic with
/// the redeemer used for spending each of the UTxOs.
/// 
/// Assumption here is that redeemers carry the staking credential of the
/// withdraw-0 validator, which is the purpose of the additional argument, i.e.
/// coercing the redeemer `Data` into an expected structure, and extracting the
/// staking credential.
pub fn one_to_one_with_redeemer(
  indices: Pairs<Int, Int>,
  spending_script_hash: ScriptHash,
  stake_script_hash: ScriptHash,
  inputs: List<Input>,
  outputs: List<Output>,
  redeemers: Pairs<ScriptPurpose, Redeemer>,
  spend_redeemer_coercer_and_stake_credential_extractor: fn(Data) ->
    (a, Credential),
  validation_logic: fn(Int, Input, a, Int, Output) -> Bool,
) -> Bool {
  let spending_credential = Script(spending_script_hash)
  let stake_credential = Script(stake_script_hash)
  let script_redeemers =
    list.foldr(
      redeemers,
      [],
      fn(redeemer, acc) {
        let Pair(redeemer_purpose, redeemer_data) = redeemer
        when redeemer_purpose is {
          Spend(_) -> {
            let (coerced_redeemer, stake_credential_from_spend_redeemer) =
              spend_redeemer_coercer_and_stake_credential_extractor(
                redeemer_data,
              )
            if stake_credential == stake_credential_from_spend_redeemer {
              list.push(acc, coerced_redeemer)
            } else {
              acc
            }
          }
          _ -> acc
        }
      },
    )
  let
    processed_redeemers,
    _,
    _,
    _,
  <-
    list_extra.foldl4(
      indices,
      script_redeemers,
      -1,
      -1,
      0,
      fn(curr_in_out_indices, remaining_script_redeemers, in0, out0, i, return) {
        when remaining_script_redeemers is {
          [] -> fail @"Too many indices specified"
          [script_redeemer, ..rest_of_script_redeemers] -> {
            let Pair(in1, out1) = curr_in_out_indices
            if in1 > in0 && out1 > out0 {
              expect Some(in_utxo) = inputs |> list.at(in1)
              expect Some(out_utxo) = outputs |> list.at(out1)
              expect
                in_utxo.output.address.payment_credential == spending_credential
              if validation_logic(in1, in_utxo, script_redeemer, out1, out_utxo) {
                return(rest_of_script_redeemers, in1, out1, i + 1)
              } else {
                fail @"Validation failed"
              }
            } else {
              // Input and output indices must be ordered to disallow duplicates.
              fail @"Input and output indices must be in ascending orders"
            }
          }
        }
      },
    )
  expect processed_redeemers == []
  True
}

//// In some cases, validators need to be aware of instances of a parameterized
//// script in order to have a more robust control over the flow of assets.
//// 
//// As a simple example, consider a minting script that needs to ensure the
//// destination of its tokens can only be instances of a specific spending
//// script, e.g. parameterized by users' wallets.
//// 
//// Since each different wallet leads to a different script address, without
//// verifying instances, instances can only be seen as arbitrary scripts from
//// the minting script's point of view.
//// 
//// This can be resolved by validating an instance is the result of applying
//// specific parameters to a given parameterized script.
//// 
//// To allow this validation on-chain, some restrictions are needed:
//// 1. Parameters of the script must have constant lengths, which can be
////    achieved by having them hashed
//// 2. Consequently, for each transaction, the resolved value of those
////    parameters must be provided through the redeemer
//// 3. The dependent script must be provided with CBOR bytes of instances
////    before and after the parameter(s)
//// 4. Wrapping of instances' logics in an outer function so that there'll be
////    single occurances of each parameter
//// 
//// This pattern provides two sets of functions. One for applying parameter(s)
//// in the dependent script (i.e. the minting script in the example above), and
//// one for wrapping your parameterized scripts with.
//// 
//// After defining your parameterized scripts, you'll need to generate
//// instances of them with dummy data in order to obtain the required `prefix`
//// value for your target script to utilize. Note that your prefix should be
//// from a single CBOR encoded result.

use aiken/builtin
use aiken/crypto.{Blake2b_224, Hash, ScriptHash, blake2b_224}
use aiken/primitive/bytearray

const param_header_28_bytes = #"004c011e581c"

const postfix: ByteArray = #"0001"

fn append_first_param_to_prefix(
  version: Int,
  prefix: ByteArray,
  param: ByteArray,
) -> ByteArray {
  builtin.integer_to_bytearray(True, 1, version)
    |> bytearray.concat(prefix)
    |> bytearray.concat(blake2b_224(param))
}

fn append_param(prefix: ByteArray, param: ByteArray) -> ByteArray {
  prefix
    |> bytearray.concat(blake2b_224(param))
}

fn append_first_prehashed_param_to_prefix(
  version: Int,
  prefix: ByteArray,
  param: ByteArray,
) -> ByteArray {
  builtin.integer_to_bytearray(True, 1, version)
    |> bytearray.concat(prefix)
    |> bytearray.concat(param)
}

/// Use this inside your contracts that depend on scripts with single
/// parameters. The parameter must be serialised before getting passed here.
/// It'll be hashed with `blake2b_224` before placement after `prefix`.
///
/// Note that your prefix should be from a single CBOR encoded result. And also,
/// the version should either be 1, 2, or 3 depending on your script.
pub fn apply_param(
  version: Int,
  prefix: ByteArray,
  param: ByteArray,
) -> ScriptHash {
  append_first_param_to_prefix(version, prefix, param)
    |> bytearray.concat(postfix)
    |> blake2b_224
}

/// Similar to [`apply_param`](#apply_param), but for scripts that their
/// parameters don't need to be resolved (e.g. have a script hash as their
/// parameter).
///
/// Can be used for any hashing algorithms, i.e. the length of the provided hash
/// does not matter (`prefix` covers it).
pub fn apply_prehashed_param(
  version: Int,
  prefix: ByteArray,
  param: ByteArray,
) -> ScriptHash {
  append_first_prehashed_param_to_prefix(version, prefix, param)
    |> bytearray.concat(postfix)
    |> blake2b_224
}

/// Similar to [`apply_param`](#apply_param), but for scripts with 2 parameters.
pub fn apply_param_2(
  version: Int,
  prefix: ByteArray,
  param_0: ByteArray,
  param_1: ByteArray,
) -> ScriptHash {
  append_first_param_to_prefix(version, prefix, param_0)
    |> bytearray.concat(param_header_28_bytes)
    |> append_param(param_1)
    |> bytearray.concat(postfix)
    |> blake2b_224
}

/// Similar to [`apply_prehashed_param`](#apply_prehashed_param), but for
/// scripts with 2 parameters.
///
/// Note that while the first parameter (`param_0`) can still be of any length,
/// `blake2b_224` is the presumed hashing algorithm for the second parameter,
/// i.e. the parameter is expected to be 28 bytes long.
pub fn apply_prehashed_param_2(
  version: Int,
  prefix: ByteArray,
  param_0: ByteArray,
  param_1: ByteArray,
) -> ScriptHash {
  append_first_prehashed_param_to_prefix(version, prefix, param_0)
    |> bytearray.concat(param_header_28_bytes)
    |> bytearray.concat(param_1)
    |> bytearray.concat(postfix)
    |> blake2b_224
}

/// Similar to [`apply_param`](#apply_param), but for scripts with 3 parameters.
pub fn apply_param_3(
  version: Int,
  prefix: ByteArray,
  param_0: ByteArray,
  param_1: ByteArray,
  param_2: ByteArray,
) -> ScriptHash {
  append_first_param_to_prefix(version, prefix, param_0)
    |> bytearray.concat(param_header_28_bytes)
    |> append_param(param_1)
    |> bytearray.concat(param_header_28_bytes)
    |> append_param(param_2)
    |> bytearray.concat(postfix)
    |> blake2b_224
}

/// Similar to [`apply_prehashed_param`](#apply_prehashed_param), but for
/// scripts with 3 parameters.
///
/// Here again the first parameter can be of arbitrary length, while the other
/// two must be 28 bytes long.
pub fn apply_prehashed_param_3(
  version: Int,
  prefix: ByteArray,
  param_0: ByteArray,
  param_1: ByteArray,
  param_2: ByteArray,
) -> ScriptHash {
  append_first_prehashed_param_to_prefix(version, prefix, param_0)
    |> bytearray.concat(param_header_28_bytes)
    |> bytearray.concat(param_1)
    |> bytearray.concat(param_header_28_bytes)
    |> bytearray.concat(param_2)
    |> bytearray.concat(postfix)
    |> blake2b_224
}

/// Datatype for redeemer of your single parameterized scripts.
pub type ParameterizedRedeemer<p, r> {
  param: p,
  redeemer: r,
}

/// Helper function for parameterized scripts, which takes care of validating
/// resolved parameter hashes, provides you with both the parameter, and your
/// custom redeemer.
pub fn wrapper(
  hashed_parameter: Hash<Blake2b_224, p>,
  parameter_serialiser: fn(p) -> ByteArray,
  outer_redeemer: ParameterizedRedeemer<p, redeemer>,
  validator_function: fn(p, redeemer) -> Bool,
) -> Bool {
  let ParameterizedRedeemer { param, redeemer } = outer_redeemer
  expect blake2b_224(parameter_serialiser(param)) == hashed_parameter
  validator_function(param, redeemer)
}

pub type ParameterizedRedeemer2<p, q, r> {
  param_0: p,
  param_1: q,
  redeemer: r,
}

pub fn wrapper_2(
  hashed_parameter_0: Hash<Blake2b_224, p>,
  hashed_parameter_1: Hash<Blake2b_224, q>,
  parameter_serialiser_0: fn(p) -> ByteArray,
  parameter_serialiser_1: fn(q) -> ByteArray,
  outer_redeemer: ParameterizedRedeemer2<p, q, r>,
  validator_function: fn(p, q, r) -> Bool,
) -> Bool {
  let ParameterizedRedeemer2 { param_0, param_1, redeemer } = outer_redeemer
  expect and {
      blake2b_224(parameter_serialiser_0(param_0)) == hashed_parameter_0,
      blake2b_224(parameter_serialiser_1(param_1)) == hashed_parameter_1,
    }
  validator_function(param_0, param_1, redeemer)
}

pub type ParameterizedRedeemer3<p, q, s, r> {
  param_0: p,
  param_1: q,
  param_2: s,
  redeemer: r,
}

pub fn wrapper_3(
  hashed_parameter_0: Hash<Blake2b_224, p>,
  hashed_parameter_1: Hash<Blake2b_224, q>,
  hashed_parameter_2: Hash<Blake2b_224, s>,
  parameter_serialiser_0: fn(p) -> ByteArray,
  parameter_serialiser_1: fn(q) -> ByteArray,
  parameter_serialiser_2: fn(s) -> ByteArray,
  outer_redeemer: ParameterizedRedeemer3<p, q, s, r>,
  validator_function: fn(p, q, s, r) -> Bool,
) -> Bool {
  let ParameterizedRedeemer3 { param_0, param_1, param_2, redeemer } =
    outer_redeemer
  expect and {
      blake2b_224(parameter_serialiser_0(param_0)) == hashed_parameter_0,
      blake2b_224(parameter_serialiser_1(param_1)) == hashed_parameter_1,
      blake2b_224(parameter_serialiser_2(param_2)) == hashed_parameter_2,
    }
  validator_function(param_0, param_1, param_2, redeemer)
}

/// Datatype for parameterized scripts that don't need a redeemer.
pub type Parameter<p> {
  param: p,
}

/// Wrapper function for scripts with one parameter that don't need a redeemer.
pub fn wrapper_no_redeemer(
  hashed_parameter: Hash<Blake2b_224, p>,
  parameter_serialiser: fn(p) -> ByteArray,
  outer_redeemer: Parameter<p>,
  validator_function: fn(p) -> Bool,
) -> Bool {
  let Parameter { param } = outer_redeemer
  expect blake2b_224(parameter_serialiser(param)) == hashed_parameter
  validator_function(param)
}

pub type Parameter2<p, q> {
  param_0: p,
  param_1: q,
}

pub fn wrapper_no_redeemer_2(
  hashed_parameter_0: Hash<Blake2b_224, p>,
  hashed_parameter_1: Hash<Blake2b_224, q>,
  parameter_serialiser_0: fn(p) -> ByteArray,
  parameter_serialiser_1: fn(q) -> ByteArray,
  outer_redeemer: Parameter2<p, q>,
  validator_function: fn(p, q) -> Bool,
) -> Bool {
  let Parameter2 { param_0, param_1 } = outer_redeemer
  expect and {
      blake2b_224(parameter_serialiser_0(param_0)) == hashed_parameter_0,
      blake2b_224(parameter_serialiser_1(param_1)) == hashed_parameter_1,
    }
  validator_function(param_0, param_1)
}

pub type Parameter3<p, q, s> {
  param_0: p,
  param_1: q,
  param_2: s,
}

pub fn wrapper_no_redeemer_3(
  hashed_parameter_0: Hash<Blake2b_224, p>,
  hashed_parameter_1: Hash<Blake2b_224, q>,
  hashed_parameter_2: Hash<Blake2b_224, q>,
  parameter_serialiser_0: fn(p) -> ByteArray,
  parameter_serialiser_1: fn(q) -> ByteArray,
  parameter_serialiser_2: fn(s) -> ByteArray,
  outer_redeemer: Parameter3<p, q, s>,
  validator_function: fn(p, q, s) -> Bool,
) -> Bool {
  let Parameter3 { param_0, param_1, param_2 } = outer_redeemer
  expect and {
      blake2b_224(parameter_serialiser_0(param_0)) == hashed_parameter_0,
      blake2b_224(parameter_serialiser_1(param_1)) == hashed_parameter_1,
      blake2b_224(parameter_serialiser_2(param_2)) == hashed_parameter_2,
    }
  validator_function(param_0, param_1, param_2)
}

use aiken/collection/list
use cardano/transaction.{Input, Output, OutputReference}

/// Helper function to be defined in the spending endpoint of your contract, for
/// appointing an input at `input_index` against an output at `output_index`. By
/// including this in your spending endpoint, you'll get an efficient access to
/// your input, and its corresponding output.
///
/// Within the function you pass as `validation_logic`, you have access to the
/// picked input and output.
///
/// Apart from `validation_logic`, the only other validation this function
/// performs for you is the equality of the picked input's output reference with
/// the one extracted from [`ScriptInfo`](https://aiken-lang.github.io/stdlib/cardano/script_context.html#ScriptInfo).
///
/// `double_satisfaction_prevented` is a required `Bool`, which is just a
/// reminder that this function does NOT cover the
/// [double satisfaction](https://github.com/Plutonomicon/plutonomicon/blob/b6906173c3f98fb5d7b40fd206f9d6fe14d0b03b/vulnerabilities.md#double-satisfaction)
/// vulnerability out-of-the-box.
pub fn one_to_one(
  input_index: Int,
  output_index: Int,
  own_ref: OutputReference,
  inputs: List<Input>,
  outputs: List<Output>,
  double_satisfaction_prevented: Bool,
  validation_logic: fn(Input, Output) -> Bool,
) -> Bool {
  expect double_satisfaction_prevented
  expect Some(Input { output_reference: in_ref, .. } as in_input) =
    inputs |> list.at(input_index)

  expect Some(out_utxo) = outputs |> list.at(output_index)

  // Indicated input must match the spending one.
  expect own_ref == in_ref

  validation_logic(in_input, out_utxo)
}

/// Helper function for appointing an input against a set of outputs in a
/// transaction. Similar to [`one_to_one`](#one_to-one), this function also
/// validates the spent UTxO's output reference matches the one found using the
/// input index.
///
/// Required validation functions are provided with:
/// 1. `Input` itself, output index, and `Output` itself (this validation is
///    executed for each output)
/// 2. `Input` itself, and the list of all `Output`s (this validation is
///    executed only once)
///
/// Here we also have the `double_satisfaction_prevented` argument as a mere
/// reminder that this function does not cover double satisfaction on its own.
pub fn one_to_many(
  input_index: Int,
  output_indices: List<Int>,
  own_ref: OutputReference,
  inputs: List<Input>,
  outputs: List<Output>,
  double_satisfaction_prevented: Bool,
  input_collective_outputs_validator: fn(Input, List<Output>) -> Bool,
  input_output_validator: fn(Input, Int, Output) -> Bool,
) -> Bool {
  expect double_satisfaction_prevented
  expect Some(input) = inputs |> list.at(input_index)

  let
    _,
    all_outputs,
  <-
    list.foldr2(
      output_indices,
      // sufficiently large index to ensure first check passes
      511,
      [],
      fn(curr_ix, prev_ix, outputs_acc, return) {
        if curr_ix < prev_ix {
          expect Some(out_utxo) = outputs |> list.at(curr_ix)
          expect input_output_validator(input, curr_ix, out_utxo)
          return(curr_ix, list.push(outputs_acc, out_utxo))
        } else {
          fail @"Output indices must be in ascending order"
        }
      },
    )

  // Indicated input must match the spending one.
  expect (own_ref == input.output_reference)?

  input_collective_outputs_validator(input, all_outputs)
}

//// This pattern allows for delegating some computations to a given staking
//// script.
//// 
//// The primary application for this is the so-called "withdraw zero trick,"
//// which is most effective for validators that need to go over multiple
//// inputs.
//// 
//// With a minimal spending logic (which is executed for each UTxO), and an
//// arbitrary withdrawal logic (which is executed only once), a much more
//// optimized script can be implemented.

use aiken/collection/list
use aiken/crypto.{ScriptHash}
use aiken_design_patterns/utils.{get_withdraw_scripts_redeemer_at}
use cardano/address.{Credential, Script}
use cardano/assets.{Lovelace}
use cardano/transaction.{Redeemer, ScriptPurpose, Withdraw}

/// Helper function for implementing validation for spending UTxOs, essentially
/// delegating their requirements to the given withdrawal validator.
///
/// In simpler terms, it says: As long as there is a redeemer with a withdrawal
/// purpose, for the given script in transaction, this UTxO can be spent.
///
/// Allows you to validate based on the withdrawal's redeemer, which ismostly
/// useful for ensuring specific endpoints are invoked.
pub fn validate_withdraw(
  withdraw_script_hash: ScriptHash,
  redeemers: Pairs<ScriptPurpose, Redeemer>,
  withdraw_redeemer_index: Int,
  withdraw_redeemer_validator: fn(Redeemer) -> Bool,
) -> Bool {
  get_withdraw_scripts_redeemer_at(
    withdraw_script_hash,
    redeemers,
    withdraw_redeemer_index,
  )
    |> withdraw_redeemer_validator
}

/// Similar to [`validate_withdraw`](#validate_withdraw), but with the
/// additional steps for extracting the withdrawal amount from the withdrawals
/// field.
pub fn validate_withdraw_with_amount(
  withdraw_script_hash: ScriptHash,
  redeemers: Pairs<ScriptPurpose, Redeemer>,
  withdraw_redeemer_index: Int,
  withdrawals: Pairs<Credential, Lovelace>,
  withdrawal_index: Int,
  withdraw_redeemer_validator: fn(Redeemer, Lovelace) -> Bool,
) -> Bool {
  let withdrawal_credential: Credential = Script(withdraw_script_hash)

  expect Some(withdraw_redeemer_pair) =
    redeemers |> list.at(withdraw_redeemer_index)

  expect withdraw_redeemer_pair.1st == Withdraw(withdrawal_credential)

  expect Some(withdrawal_pair) = withdrawals |> list.at(withdrawal_index)

  expect withdrawal_pair.1st == withdrawal_credential

  withdraw_redeemer_validator(withdraw_redeemer_pair.2nd, withdrawal_pair.2nd)
}

/// A more minimal version of [`validate_withdraw`](#validate_withdraw), where
/// only the presence of a given staking script is checked, regardless of
/// withdraw amount or redeemer.
pub fn validate_withdraw_minimal(
  withdraw_script_hash: ScriptHash,
  withdrawals: Pairs<Credential, Lovelace>,
  withdrawal_index: Int,
) -> Bool {
  expect Some(withdrawal_pair) = withdrawals |> list.at(withdrawal_index)

  withdrawal_pair.1st == Script(withdraw_script_hash)
}

//// This design pattern couples the spend and minting endpoints of a validator,
//// in order to have minimal spend costs, in exchange for a single execution of
//// the minting endpoint.
//// 
//// In other words, spend logic only ensures the minting endpoint executes. It
//// does so by looking at the mint field and making sure a non-zero amount of
//// its asset (i.e. with a policy identical to the provided script hash) are
//// getting minted/burnt.
//// 
//// The arbitrary logic is passed to the minting policy so that it can be
//// executed a single time for a given transaction.

use aiken/collection/dict.{Dict}
use aiken/collection/list
use cardano/assets.{AssetName, PolicyId, Value}
use cardano/transaction.{Mint, Redeemer, ScriptPurpose}

/// Function primarily meant be used in your spending validator. It looks at
/// both the redeemers, and minted tokens to allow you validate agains the
/// policy's redeemer, and its tokens getting minted/burnt.
///
/// `mint_redeemer_index` is the positional index of the policy's redeemer in
/// the `redeemers` field of the transaction.
pub fn validate_mint(
  mint_script_hash: PolicyId,
  mint: Value,
  redeemers: Pairs<ScriptPurpose, Redeemer>,
  mint_redeemer_index: Int,
  mint_validator: fn(Redeemer, Dict<AssetName, Int>) -> Bool,
) -> Bool {
  let mint_purpose = Mint(mint_script_hash)

  expect Some(rdmr_pair) = redeemers |> list.at(mint_redeemer_index)

  expect rdmr_pair.1st == mint_purpose

  let tokens = mint |> assets.tokens(mint_script_hash)

  mint_validator(rdmr_pair.2nd, tokens)
}

/// A minimal version of [`spend`](#spend), where the only validation is
/// presence of at least one minting/burning action with the given policy ID.
pub fn validate_mint_minimal(mint_script_hash: PolicyId, mint: Value) -> Bool {
  !(mint |> assets.tokens(mint_script_hash) |> dict.is_empty)
}

